    static let crcExtra: UInt8 = 71
    static let basePayloadSize: Int = 22

    var flags: UInt16 = 0
    var velocity_variance: Float = 0
    var pos_horiz_variance: Float = 0
    var pos_vert_variance: Float = 0
    var compass_variance: Float = 0
    var terrain_alt_variance: Float = 0
    var airspeed_variance: Float = 0

    init() {}

    init(from payload: Data) {
        let d = payload
        var o = 0
        if o + 4 <= d.count {
            velocity_variance = { let b = UInt32(d[d.startIndex+o]) | UInt32(d[d.startIndex+o+1]) << 8 | UInt32(d[d.startIndex+o+2]) << 16 | UInt32(d[d.startIndex+o+3]) << 24; return Float(bitPattern: b) }()
        }
        o += 4
        if o + 4 <= d.count {
            pos_horiz_variance = { let b = UInt32(d[d.startIndex+o]) | UInt32(d[d.startIndex+o+1]) << 8 | UInt32(d[d.startIndex+o+2]) << 16 | UInt32(d[d.startIndex+o+3]) << 24; return Float(bitPattern: b) }()
        }
        o += 4
        if o + 4 <= d.count {
            pos_vert_variance = { let b = UInt32(d[d.startIndex+o]) | UInt32(d[d.startIndex+o+1]) << 8 | UInt32(d[d.startIndex+o+2]) << 16 | UInt32(d[d.startIndex+o+3]) << 24; return Float(bitPattern: b) }()
        }
        o += 4
        if o + 4 <= d.count {
            compass_variance = { let b = UInt32(d[d.startIndex+o]) | UInt32(d[d.startIndex+o+1]) << 8 | UInt32(d[d.startIndex+o+2]) << 16 | UInt32(d[d.startIndex+o+3]) << 24; return Float(bitPattern: b) }()
        }
        o += 4
        if o + 4 <= d.count {
            terrain_alt_variance = { let b = UInt32(d[d.startIndex+o]) | UInt32(d[d.startIndex+o+1]) << 8 | UInt32(d[d.startIndex+o+2]) << 16 | UInt32(d[d.startIndex+o+3]) << 24; return Float(bitPattern: b) }()
        }
        o += 4
        if o + 2 <= d.count {
            flags = UInt16(d[d.startIndex+o]) | UInt16(d[d.startIndex+o+1]) << 8
        }
        o += 2
        // Extension fields (only present in longer payloads)
        guard o < d.count else { return }
        if o + 4 <= d.count {
            airspeed_variance = { let b = UInt32(d[d.startIndex+o]) | UInt32(d[d.startIndex+o+1]) << 8 | UInt32(d[d.startIndex+o+2]) << 16 | UInt32(d[d.startIndex+o+3]) << 24; return Float(bitPattern: b) }()
        }
        o += 4
    }

    func encode() -> [UInt8] {
        var p = [UInt8](repeating: 0, count: 26)
        var o = 0
        do { let b = velocity_variance.bitPattern; p[o] = UInt8(b & 0xFF); p[o+1] = UInt8((b >> 8) & 0xFF); p[o+2] = UInt8((b >> 16) & 0xFF); p[o+3] = UInt8((b >> 24) & 0xFF) }
        o += 4
        do { let b = pos_horiz_variance.bitPattern; p[o] = UInt8(b & 0xFF); p[o+1] = UInt8((b >> 8) & 0xFF); p[o+2] = UInt8((b >> 16) & 0xFF); p[o+3] = UInt8((b >> 24) & 0xFF) }
        o += 4
        do { let b = pos_vert_variance.bitPattern; p[o] = UInt8(b & 0xFF); p[o+1] = UInt8((b >> 8) & 0xFF); p[o+2] = UInt8((b >> 16) & 0xFF); p[o+3] = UInt8((b >> 24) & 0xFF) }
        o += 4
        do { let b = compass_variance.bitPattern; p[o] = UInt8(b & 0xFF); p[o+1] = UInt8((b >> 8) & 0xFF); p[o+2] = UInt8((b >> 16) & 0xFF); p[o+3] = UInt8((b >> 24) & 0xFF) }
        o += 4
        do { let b = terrain_alt_variance.bitPattern; p[o] = UInt8(b & 0xFF); p[o+1] = UInt8((b >> 8) & 0xFF); p[o+2] = UInt8((b >> 16) & 0xFF); p[o+3] = UInt8((b >> 24) & 0xFF) }
        o += 4
        do { let v = UInt16(truncatingIfNeeded: flags); p[o] = UInt8(v & 0xFF); p[o+1] = UInt8((v >> 8) & 0xFF) }
        o += 2
        do { let b = airspeed_variance.bitPattern; p[o] = UInt8(b & 0xFF); p[o+1] = UInt8((b >> 8) & 0xFF); p[o+2] = UInt8((b >> 16) & 0xFF); p[o+3] = UInt8((b >> 24) & 0xFF) }
        o += 4
        return p
    }
}

