/// GPS_RTCM_DATA (#233)
struct MsgGpsRtcmData: Sendable {
    static let id: UInt32 = 233
    static let crcExtra: UInt8 = 35
    static let basePayloadSize: Int = 182

    var flags: UInt8 = 0
    var len: UInt8 = 0
    var data: [UInt8] = [UInt8](repeating: 0, count: 180)

    init() {}

    init(from payload: Data) {
        let d = payload
        var o = 0
        if o + 1 <= d.count {
            flags = d[d.startIndex+o]
        }
        o += 1
        if o + 1 <= d.count {
            len = d[d.startIndex+o]
        }
        o += 1
        if o + 180 <= d.count {
            data = (0..<180).map { (i: Int) -> UInt8 in
                return d[d.startIndex+o+i*1]
            }
        }
        o += 180
    }

    func encode() -> [UInt8] {
        var p = [UInt8](repeating: 0, count: 182)
        var o = 0
        p[o] = UInt8(truncatingIfNeeded: flags)
        o += 1
        p[o] = UInt8(truncatingIfNeeded: len)
        o += 1
        for i in 0..<180 {
        p[o+i*1] = UInt8(truncatingIfNeeded: data[i])
        }
        o += 180
        return p
    }
}

